mapper.select:
SELECT id, shard_id, owner_node_id, lease_expire_at, version, update_time
FROM shard_lease
WHERE shard_id = #{shardId}

mapper.insert:
INSERT INTO shard_lease (
    shard_id, owner_node_id, lease_expire_at, version, update_time
) VALUES (
    #{shardId}, #{ownerNodeId}, #{leaseExpireAt}, #{version}, NOW()
)

mapper.update:
UPDATE shard_lease
SET lease_expire_at = #{leaseExpireAt},
    version = version + 1,
    update_time = NOW()
WHERE shard_id = #{shardId}
  AND owner_node_id = #{ownerNodeId}
  AND version = #{expectedVersion}

UPDATE shard_lease
SET owner_node_id = #{ownerNodeId},
    lease_expire_at = #{leaseExpireAt},
    version = version + 1,
    update_time = NOW()
WHERE shard_id = #{shardId}
  AND lease_expire_at  <  #{nowTime}
  AND version = #{expectedVersion}

mapper.select:
SELECT shard_id
FROM shard_lease
WHERE owner_node_id = #{ownerNodeId}
  AND lease_expire_at  >=  #{nowTime}
ORDER BY shard_id ASC
